        int leaf = st->bank.leaf[i];
        if (leaf < 0 || leaf >= st->grid.n) continue;
        double vol = st->grid.cells[leaf].vol;
        if (vol <= 0.0) continue;
        for (int v = 0; v < NVAR; v++) {
            st->grid.cells[leaf].q[v] += st->bank.flux[i * NVAR + v] / vol;
        }
    }
}

